from itertools import combinations, product
from typing import Callable, Iterable
from rbcsv import Colorings, ColoringsK
import math


def check(n: int, sets: list[set], func: Callable = None, all: bool = False, power: int = 2):
    # Returns False if no coloring is found, otherwise returns valid triple (or whatever the callback returns)
    if func: # Only works with triples
        return _check(sets, func)
    
    # Get all solutions, only supported by default eq. x+y=z^2
    if all:
        arr = []

    # Ridiculously inefficient brute force approach
    # Much room for optimization wrt combining coloring and checking in order to do exhaustive search better
    # Mainly useful for getting many examples of colorings instead of one, only feasible on small n
    colors = len(sets)

    # Compute all squares for each color
    squares = list([set() for i in sets])
    for i in range(colors):
        for j in sets[i]:
            squares[i].add((j ** power) % n)

    # Plug in every triple to check for rainbow solution
    for i in range(colors):     # This is our z color
        _sets = sets.copy()
        _sets.pop(i)            # Get set of remaining colors
        for s1, s2 in combinations(_sets, 2):   # Grab every pair of sets
            for x,y in product(s1, s2):
                if (x + y) % n in squares[i]:   # If any produce a square we've computed, it's a solution
                    z = _recover(n, sets[i], (x + y) % n, power)
                    if all:
                        arr.append((x, y, z))
                    else:
                        return (x, y, z)
    
    return arr if all else False


def _recover(n: int, s: set[int], v: int, power: int):
    # Gets a valid root of the quadratic residue, not necessarily unique
    for i in s:
        if (i ** power) % n == v:
            return i
                    

def _check(sets: list[set], func: Callable):
    # Less efficient, but custom. Doesn't consider commutativity
    for i in range(len(sets)):
        _sets = sets.copy()
        _sets.pop(i)
        for s1, s2, s3 in combinations(_sets, 3):
            for x, y, z in product(s1, s2, s3):
                if (func(x,y,z)):
                    return True, x, y, z
        return False
    

def coloring(*colors: Iterable, n: int = 0, notify: bool = True):
    # Converts groups of numbers into a list of sets used by other functions
    # Optional arg n will add all unused numbers <n into their own distinct color
    sets = list([set(color) for color in colors])
    if n:
        union = set()
        for s in sets:
            union.update(s)
        if len(union) < n:
            if notify: print(f"Adding {n - len(union)} elements to a new color...")
            sets.append({i for i in range(n) if i not in union})
    return sets


def symmetry(n: int, sets: list[set]):
    result = list([True for i in range(len(sets))])
    for i in range(len(sets)):
        for j in sets[i]:
            if (-j) % n not in sets[i]:
                result[i] = False
                break
    return result


def store(sets: list[set]):
    return frozenset([frozenset(s) for s in sets])


def find(i: int, sets: list[set]):
    for j in range(len(sets)):
        if i in sets[j]:
            return j


def periodicity(n: int, p: int, s1: set, s2: set):
    # We try powers of p, and ask "are we symmetric mod p^k?"
    max_k = round(math.log(n, p))
    periods: list = []
    for k in range(1,max_k + 1):
        bad = False
        mod = p ** k
        # for bound in range(0,n,mod):
            # for j in range(bound,bound + mod):
        for j in range(mod):    # Doesn't cover enough but I don't care enough to include exceptions for (important) special cases
            if j in s1 and mod-j not in s1 and (j ** 2) % n != 0:
                bad = True
                break
            # if bad: break   # Useless since we pull some special multiples of p^k out
        periods.append(0 if bad else 1)
    return periods


def c1():
    p = 13

    t1 = (1,5,8,12)
    t2 = [i for i in range(1,p) if i not in t1]
    p2 = p**2
    p3 = p**3
    p4 = p**4

    color = [
        {0}
    ]

    for i in range(1,int((p+1)/2)):
        color.append({i * p3, p4 - i * p3})


    def f(i):
        for c in color:
            if i in c:
                return True
        return False

    color.append({i for i in range(p4) if i % p in t1 and not f(i)})
    color.append({i for i in range(p4) if i % p in t2 and not f(i)})
    color.append({i for i in range(p,p4,p) if int(i/p) % p in t1 and not f(i)})
    color[-1] = color[-1].union({i for i in range(p2,p4,p2) if int(i/p2) % p in t1})
    color.append({i for i in range(p,p4,p) if int(i/p) % p in t2 and not f(i)})
    color[-1] = color[-1].union({i for i in range(p2,p4,p2) if int(i/p2) % p in t2})

    color = coloring(*color,n=p**4,notify=True)
    print(check(p4, color))

def c2():
    p = 7
    colors: list[set] = []
    for i in range(0,int((p**2+1)/2),p):
        s = set()
        for p2 in range(0,p**3,p**2):
            s.add(i+p2)
            s.add(p**2-i+p2)
        colors.append(s)
    n=329
    d=int((n%(p**2))/p)
    if d > (p-1)/2: d = p-d
    colors[d].remove(n)
    colors[d].remove(p**3-n)
    colors.append({n, p**3-n})
    for c in colors: print(c)
    print(check(p**3, colors))

def c3():
    p,q = 3,5
    n=p**2*q**2
    
    colors = [
        {0},
    ]
    for i in range(p*q,round((n+1)/2),p*q):
        colors.append({i,n-i})
    # print(colors)
    colors.append(set())
    for i in range(q,n,q):
        if i % p == 0: continue
        colors[-1].add(i)
    # print(colors)
    print(check(n, coloring(*colors, n=n)))
    colors = coloring(*colors, n=n)
    print(len(colors))



